//! Parity tests for `hymeko_graph::incidence::build_edge_incidence_vertex_adj`.
//!
//! These tests are the falsifier for the upcoming speedup refactor
//! (`docs/plans/2026-05-22-incidence-vertex-adj-fast/`).  They lock in
//! the **current** sorted-merge serial behaviour against a slow but
//! obviously-correct brute-force reference: per query edge, build
//! `adj_u ∪ adj_v` as a `HashSet`, drop the self-edge if present,
//! emit triplet at `1 / |N|`.
//!
//! When the parallel / bitset / CSR fast paths land, they must equal
//! the brute force *modulo row order* — these tests assert that
//! row-by-row.
//!
//! Fixture: 200-vertex, ~3500-edge signed graph generated by a
//! seeded LCG.  Big enough that:
//!   * mean degree ≈ 35, similar to Slashdot k=4 hot loop;
//!   * the sorted-merge dedup path is exercised on real overlaps;
//!   * the test runs in < 1 s, well under the CLAUDE.md §3 budget.
//!
//! 2026-05-22 — Phase 0 of the incidence-vertex-adj-fast refactor.

use std::collections::HashSet;

use hymeko_graph::incidence::{
    build_edge_incidence, build_edge_incidence_vertex_adj, BuildOpts, IncidenceCoo,
    IncidenceOutput, IncidenceResult,
};
use hymeko_graph::rand_lcg::Lcg;

// ─────────────────────────────────────────────────────────────────────
// Fixture builder
// ─────────────────────────────────────────────────────────────────────

struct Fixture {
    /// Query edges (paired u32 endpoints).
    edges_u: Vec<u32>,
    edges_v: Vec<u32>,
    /// Vertex-to-tuples CSR (sorted within each row).
    csr_row_ptr: Vec<u32>,
    csr_col_idx: Vec<u32>,
    /// Sorted-pair self-edge map (k=2 cycles).
    self_keys_u: Vec<u32>,
    self_keys_v: Vec<u32>,
    self_tuple_idx: Vec<u32>,
}

/// Build a deterministic mid-size signed graph:
///   * `n_vertices` vertices
///   * `n_tuples` "cycles" (each is a pair of vertex indices, so this
///     doubles as a k=2 set — enough to exercise the self-edge path)
///   * For each tuple `t = (a, b)`, both `a` and `b` get `t` added to
///     their adjacency list.  We dedup within a vertex (a vertex can
///     belong to many tuples but not the same one twice).
///
/// All seeds are LCG-driven, so the fixture is reproducible across
/// platforms and across runs.
fn build_fixture(seed: u64, n_vertices: u32, n_tuples: u32) -> Fixture {
    let mut rng = Lcg::new(seed);
    // ---- 1. Sample tuples (vertex pairs) ----
    let mut tuples: Vec<(u32, u32)> = Vec::with_capacity(n_tuples as usize);
    let mut seen: HashSet<(u32, u32)> = HashSet::new();
    while (tuples.len() as u32) < n_tuples {
        let a = rng.next_in_range(n_vertices);
        let b = rng.next_in_range(n_vertices);
        if a == b {
            continue;
        }
        let key = if a < b { (a, b) } else { (b, a) };
        if seen.insert(key) {
            tuples.push((a, b));
        }
    }

    // ---- 2. Build CSR vertex → tuple adjacency ----
    //
    // (vertex, tuple) flat pairs, then group-by vertex into CSR.
    let mut flat: Vec<(u32, u32)> = Vec::with_capacity(tuples.len() * 2);
    for (t_idx, &(a, b)) in tuples.iter().enumerate() {
        let t = t_idx as u32;
        flat.push((a, t));
        flat.push((b, t));
    }
    flat.sort();
    let mut csr_row_ptr: Vec<u32> = vec![0; (n_vertices + 1) as usize];
    let mut csr_col_idx: Vec<u32> = Vec::with_capacity(flat.len());
    let mut cur_v: u32 = 0;
    for &(v, t) in &flat {
        // Advance row_ptr to the start of this vertex.
        while cur_v < v {
            cur_v += 1;
            csr_row_ptr[cur_v as usize] = csr_col_idx.len() as u32;
        }
        // Dedup: skip if this tuple already appended for this vertex.
        if csr_col_idx
            .last()
            .copied()
            .zip(Some(csr_row_ptr[cur_v as usize]))
            .map(|(last, start)| {
                csr_col_idx.len() as u32 > start && last == t
            })
            .unwrap_or(false)
        {
            continue;
        }
        csr_col_idx.push(t);
    }
    // Tail: fill remaining row_ptr entries.
    while (cur_v as usize) < n_vertices as usize {
        cur_v += 1;
        csr_row_ptr[cur_v as usize] = csr_col_idx.len() as u32;
    }

    // ---- 3. Sample query edges ----
    let n_queries = n_tuples / 2; // half the tuples → query edges
    let mut edges_u: Vec<u32> = Vec::with_capacity(n_queries as usize);
    let mut edges_v: Vec<u32> = Vec::with_capacity(n_queries as usize);
    let mut q_seen: HashSet<(u32, u32)> = HashSet::new();
    while (edges_u.len() as u32) < n_queries {
        let u = rng.next_in_range(n_vertices);
        let v = rng.next_in_range(n_vertices);
        if u == v {
            continue;
        }
        let key = if u < v { (u, v) } else { (v, u) };
        if q_seen.insert(key) {
            edges_u.push(u);
            edges_v.push(v);
        }
    }

    // ---- 4. Self-edge map: every tuple is a (vertex, vertex) pair, so
    //         every tuple is itself a candidate self-edge.  This gives
    //         the most-exercised path: roughly half the queries will
    //         have a self-edge to exclude. ----
    let mut self_keys_u: Vec<u32> = Vec::with_capacity(tuples.len());
    let mut self_keys_v: Vec<u32> = Vec::with_capacity(tuples.len());
    let mut self_tuple_idx: Vec<u32> = Vec::with_capacity(tuples.len());
    for (t_idx, &(a, b)) in tuples.iter().enumerate() {
        let (lo, hi) = if a < b { (a, b) } else { (b, a) };
        self_keys_u.push(lo);
        self_keys_v.push(hi);
        self_tuple_idx.push(t_idx as u32);
    }

    Fixture {
        edges_u,
        edges_v,
        csr_row_ptr,
        csr_col_idx,
        self_keys_u,
        self_keys_v,
        self_tuple_idx,
    }
}

// ─────────────────────────────────────────────────────────────────────
// Brute-force reference implementation
// ─────────────────────────────────────────────────────────────────────

/// Slow but clearly-correct.  Per query edge, build `adj_u ∪ adj_v`
/// as a `HashSet`, drop the self-edge if present, emit triplet with
/// uniform `1 / |N|` weight.  This is the protocol authority that
/// every fast path must agree with.
fn brute_force(fix: &Fixture) -> IncidenceCoo {
    let mut self_map: std::collections::HashMap<(u32, u32), u32> =
        std::collections::HashMap::new();
    for i in 0..fix.self_keys_u.len() {
        self_map.insert(
            (fix.self_keys_u[i], fix.self_keys_v[i]),
            fix.self_tuple_idx[i],
        );
    }

    let mut rows = Vec::new();
    let mut cols = Vec::new();
    let mut vals = Vec::new();
    let n_nodes = fix.csr_row_ptr.len().saturating_sub(1);

    for ei in 0..fix.edges_u.len() {
        let u = fix.edges_u[ei];
        let v = fix.edges_v[ei];
        if (u as usize) >= n_nodes || (v as usize) >= n_nodes {
            continue;
        }
        let u_lo = fix.csr_row_ptr[u as usize] as usize;
        let u_hi = fix.csr_row_ptr[u as usize + 1] as usize;
        let v_lo = fix.csr_row_ptr[v as usize] as usize;
        let v_hi = fix.csr_row_ptr[v as usize + 1] as usize;

        let mut union: HashSet<u32> = HashSet::new();
        for &t in &fix.csr_col_idx[u_lo..u_hi] {
            union.insert(t);
        }
        for &t in &fix.csr_col_idx[v_lo..v_hi] {
            union.insert(t);
        }
        let (k_lo, k_hi) = if u < v { (u, v) } else { (v, u) };
        if let Some(&self_t) = self_map.get(&(k_lo, k_hi)) {
            union.remove(&self_t);
        }
        if union.is_empty() {
            continue;
        }
        let w = 1.0_f32 / union.len() as f32;
        let mut sorted: Vec<u32> = union.into_iter().collect();
        sorted.sort();
        for t in sorted {
            rows.push(ei as u32);
            cols.push(t);
            vals.push(w);
        }
    }

    IncidenceCoo { rows, cols, vals }
}

// ─────────────────────────────────────────────────────────────────────
// Parity assertion (row-set equality, tolerant of row order)
// ─────────────────────────────────────────────────────────────────────

/// Group COO triplet by row index.  Each value is the sorted list of
/// `(col, val)` pairs for that row.  Comparing two grouped views is
/// order-independent across rows AND across within-row entries (the
/// brute force already sorts within row; the fast path may not).
fn group_by_row(coo: &IncidenceCoo) -> std::collections::HashMap<u32, Vec<(u32, f32)>> {
    let mut by_row: std::collections::HashMap<u32, Vec<(u32, f32)>> =
        std::collections::HashMap::new();
    for ((r, c), v) in coo.rows.iter().zip(coo.cols.iter()).zip(coo.vals.iter()) {
        by_row.entry(*r).or_default().push((*c, *v));
    }
    for v in by_row.values_mut() {
        v.sort_by_key(|&(c, _)| c);
    }
    by_row
}

fn assert_parity(actual: &IncidenceCoo, reference: &IncidenceCoo) {
    let a = group_by_row(actual);
    let r = group_by_row(reference);

    assert_eq!(
        a.len(),
        r.len(),
        "row count mismatch: actual={} reference={}",
        a.len(),
        r.len(),
    );

    for (row, ref_entries) in &r {
        let act_entries = a.get(row).unwrap_or_else(|| {
            panic!("row {} present in reference but absent in actual", row)
        });
        assert_eq!(
            act_entries.len(),
            ref_entries.len(),
            "row {} cardinality mismatch: actual={} reference={}",
            row,
            act_entries.len(),
            ref_entries.len(),
        );
        for ((ac, av), (rc, rv)) in act_entries.iter().zip(ref_entries.iter()) {
            assert_eq!(ac, rc, "row {} col mismatch", row);
            assert!(
                (av - rv).abs() < 1e-6,
                "row {} val mismatch: actual={} reference={}",
                row,
                av,
                rv,
            );
        }
    }
}

// ─────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────

#[test]
fn parity_small_graph_against_brute_force() {
    let fix = build_fixture(0xC0FFEE, 50, 200);
    let actual = build_edge_incidence_vertex_adj(
        &fix.edges_u,
        &fix.edges_v,
        &fix.csr_row_ptr,
        &fix.csr_col_idx,
        &fix.self_keys_u,
        &fix.self_keys_v,
        &fix.self_tuple_idx,
    )
    .expect("serial path returns ok");
    let reference = brute_force(&fix);
    assert_parity(&actual, &reference);
    // Sanity: non-empty result.
    assert!(!actual.rows.is_empty(), "fixture too small: no rows emitted");
}

#[test]
fn parity_mid_graph_against_brute_force() {
    // 200 vertices, ~3500 tuples — mean degree ≈ 35, the Slashdot
    // k=4 hot-loop regime.  Verifies parity at production-shape scale.
    let fix = build_fixture(0x5EEDED, 200, 3500);
    let actual = build_edge_incidence_vertex_adj(
        &fix.edges_u,
        &fix.edges_v,
        &fix.csr_row_ptr,
        &fix.csr_col_idx,
        &fix.self_keys_u,
        &fix.self_keys_v,
        &fix.self_tuple_idx,
    )
    .expect("serial path returns ok");
    let reference = brute_force(&fix);
    assert_parity(&actual, &reference);
    assert!(
        actual.rows.len() > 1000,
        "mid fixture should emit > 1000 triplets, got {}",
        actual.rows.len(),
    );
}

#[test]
fn parity_with_no_self_edges() {
    // Same vertices + CSR but pass no self-map.  Every query edge
    // keeps its full union → larger output.
    let fix = build_fixture(0xC0FFEE, 50, 200);
    let actual = build_edge_incidence_vertex_adj(
        &fix.edges_u,
        &fix.edges_v,
        &fix.csr_row_ptr,
        &fix.csr_col_idx,
        &[],
        &[],
        &[],
    )
    .expect("serial path returns ok");
    let no_self_fix = Fixture {
        self_keys_u: vec![],
        self_keys_v: vec![],
        self_tuple_idx: vec![],
        ..build_fixture(0xC0FFEE, 50, 200)
    };
    let reference = brute_force(&no_self_fix);
    assert_parity(&actual, &reference);
}

#[test]
fn parity_handles_out_of_bound_query() {
    // One query with an out-of-bounds endpoint — should be silently
    // skipped (the prior 6 unit tests already cover this; here we
    // confirm the brute force agrees).
    let mut fix = build_fixture(0xC0FFEE, 50, 200);
    fix.edges_u.push(9999);
    fix.edges_v.push(0);
    let actual = build_edge_incidence_vertex_adj(
        &fix.edges_u,
        &fix.edges_v,
        &fix.csr_row_ptr,
        &fix.csr_col_idx,
        &fix.self_keys_u,
        &fix.self_keys_v,
        &fix.self_tuple_idx,
    )
    .expect("serial path returns ok");
    let reference = brute_force(&fix);
    assert_parity(&actual, &reference);
}

// ---- BuildOpts dispatch parity ----

fn call_with_opts(fix: &Fixture, opts: BuildOpts) -> IncidenceCoo {
    match build_edge_incidence(
        &fix.edges_u,
        &fix.edges_v,
        &fix.csr_row_ptr,
        &fix.csr_col_idx,
        &fix.self_keys_u,
        &fix.self_keys_v,
        &fix.self_tuple_idx,
        opts,
    )
    .expect("dispatch returns ok")
    {
        IncidenceResult::Coo(coo) => coo,
        IncidenceResult::Csr { row_ptr, cols, vals } => {
            // Re-expand CSR → COO so the parity helper can compare.
            let mut rows: Vec<u32> = Vec::with_capacity(cols.len());
            for ei in 0..(row_ptr.len() - 1) {
                let lo = row_ptr[ei] as usize;
                let hi = row_ptr[ei + 1] as usize;
                for _ in lo..hi {
                    rows.push(ei as u32);
                }
            }
            IncidenceCoo { rows, cols, vals }
        }
    }
}

#[test]
fn parity_parallel_matches_brute_force_mid_graph() {
    let fix = build_fixture(0x5EEDED, 200, 3500);
    let actual = call_with_opts(
        &fix,
        BuildOpts { parallel: true, ..BuildOpts::default() },
    );
    let reference = brute_force(&fix);
    assert_parity(&actual, &reference);
}

