#[test]
fn bitset_path_inactive_when_threshold_below_n_tuples() {
    // bitset_threshold = 100, n_tuples = 200 → bitset must NOT engage,
    // so the result must still equal brute force via the sorted-merge
    // path.  (Sanity that the threshold gate is correct.)
    let fix = build_fixture(0xC0FFEE, 50, 200);
    let actual = call_with_opts(
        &fix,
        BuildOpts {
            bitset_threshold: 100,
            ..BuildOpts::default()
        },
    );
    let reference = brute_force(&fix);
    assert_parity(&actual, &reference);
}

#[test]
fn parallel_path_preserves_row_order() {
    // Chunk-aligned row order: parallel output is in ascending row
    // order because chunk boundaries fall on multiples of
    // PARALLEL_CHUNK_SIZE (1024) and rows within a chunk are
    // ascending.  (The presort experiment 2026-05-22 was reverted
    // because it broke this property and the CSR fast path with it.)
    let fix = build_fixture(0x5EEDED, 200, 3500);
    let parallel = call_with_opts(
        &fix,
        BuildOpts { parallel: true, ..BuildOpts::default() },
    );
    for w in parallel.rows.windows(2) {
        assert!(w[0] <= w[1], "parallel row order broken at {} {}", w[0], w[1]);
    }
}

#[test]
fn fixture_is_deterministic_across_runs() {
    // Two builds with the same seed produce bit-equal CSR + queries.
    let a = build_fixture(0xDEADBEEF, 100, 500);
    let b = build_fixture(0xDEADBEEF, 100, 500);
    assert_eq!(a.csr_row_ptr, b.csr_row_ptr);
    assert_eq!(a.csr_col_idx, b.csr_col_idx);
    assert_eq!(a.edges_u, b.edges_u);
    assert_eq!(a.edges_v, b.edges_v);
    assert_eq!(a.self_tuple_idx, b.self_tuple_idx);
}
